  --xp-task-pane-top: oklch(0.2831 0.0326 269.245);
  --xp-task-pane-bottom: oklch(0.2405 0.0261 268.121);
  --xp-link: oklch(0.7537 0.089 260.792);
  --xp-bubble-user-top: oklch(0.3489 0.051 262.958);
  --xp-bubble-user-bottom: oklch(0.3023 0.0446 264.304);
  --xp-scroll-track: oklch(0.2672 0.0086 255.58);
  --xp-scroll-thumb-top: oklch(0.4102 0.0449 259.658);
  --xp-scroll-thumb-bottom: oklch(0.3466 0.0387 260.466);
  --xp-scroll-thumb-border: oklch(0.5083 0.0442 255.724);
  --xp-skeleton: oklch(0.3122 0.0099 260.713);
  --xp-solid-top: oklch(0.369 0.0159 255.615);
  --xp-solid-bottom: oklch(0.3481 0.0515 261.732);
  --xp-solid-ring: oklch(0.492 0.081 260.654);
  --xp-close-top: oklch(0.5465 0.1437 30.284);
  --xp-close-bottom: oklch(0.4553 0.1345 27.22);
}

@layer components {
  /* skin-root ergonomics: Tahoma @ 12px inherited; explicit text utilities on components still win. */
  [data-skin="xp"] [data-control-ui] {
    font-family: var(--font-sans);
    font-size: 0.75rem;
  }

  /* classic XP tab strip: baseline recipe keeps geometry/states; knobs re-value component-local vars.
     un-tokenizable Luna reading stays as rules: raised gradient boxes on the Luna desktop gray; active tab white,
     1px taller, cuts baseline, wears orange top stripe (tabs-indicator slides via Base UI --active-tab-* vars). */
  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="list"]) {
    --tabs-list-h: calc(var(--tabs-trigger-h) + 3px);
    --tabs-trigger-radius: 0px; /* squares the strip; the tab/indicator keep their own 3px tops */
    --tabs-list-bg: transparent;
    --tabs-indicator-bg: var(--xp-tab-accent);
    --tabs-indicator-shadow: none;
    --tabs-line-indicator-bg: var(--xp-tab-accent);
    align-items: flex-end;
    /* real declarations (not gap knob) on purpose: must also hold in line variant, whose baseline resets gap/padding/min-height. */
    min-height: var(--tabs-list-h);
    gap: 2px;
    border-bottom: 1px solid var(--border);
    padding: 0;
  }

  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="list"][data-variant="browser"]) {
    --tabs-indicator-bg: var(--background);
  }

  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="tab"]) {
    /* height/cursor restated (baseline values) so the single-tab reset keeps the full Luna box */
    height: var(--tabs-trigger-h);
    cursor: pointer;
    border: 1px solid var(--border);
    border-bottom: none;
    border-radius: 3px 3px 0 0;
    background: linear-gradient(180deg, var(--xp-tab-face-top) 0%, var(--xp-tab-face-bottom) 100%);
    padding-inline: 0.75rem;
    font-weight: 400;
    color: var(--foreground);
    transition: color var(--duration-fast) var(--ease-standard);
  }

  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="tab"][aria-selected="true"]),
  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="tab"][data-active]) {
    height: calc(var(--tabs-trigger-h) + 2px);
    margin-bottom: -1px;
    background: var(--background);
    color: var(--foreground);
  }

  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="tab"]:focus-visible) {
    box-shadow: none;
    outline: 1px dotted var(--foreground);
    outline-offset: -3px;
  }

  [data-skin="xp"] :where([data-control-ui="tabs"][data-slot="indicator"]) {
    top: 1px;
    bottom: auto;
    z-index: 2;
    height: 3px;
    transform: translateX(var(--active-tab-left));
    border-radius: 3px 3px 0 0; /* also caps the line variant's pill indicator, as before */
  }
}

/* xp-bevel-up: raised toolbar edge (light top-left, dark bottom-right); buttons flat until hover pops this. */
@utility xp-bevel-up {
  box-shadow:
    inset 1px 1px 0 var(--xp-bevel-light),
    inset -1px -1px 0 var(--xp-bevel-dark);
}

/* xp-bevel-down — the pressed reading: the bevel inverts so the control sinks into the surface. */
@utility xp-bevel-down {
  box-shadow:
    inset 1px 1px 0 var(--xp-bevel-dark),
    inset -1px -1px 0 var(--xp-bevel-light);
}

/* xp-gloss: bright wash over top half of surface; painted on ::before, content should sit above z-0. */
@utility xp-gloss {
  position: relative;

  &::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0 0 45% 0;
    border-radius: inherit;
    background: linear-gradient(180deg, oklch(1 0 0 / 0.55) 0%, oklch(1 0 0 / 0.08) 100%);
  }
}

/* xp-pinstripes — the faint vertical Luna watermark texture for wide surfaces. */
@utility xp-pinstripes {
  background-image: repeating-linear-gradient(
    90deg,
    oklch(from var(--foreground) l c h / 0.03) 0 1px,
    transparent 1px 4px
  );
}

/* xp-scroll-track: XP scrollbar channel; used by ScrollArea slot, pair with xp-scroll-thumb. */
@utility xp-scroll-track {
  border-radius: 0;
  background: var(--xp-scroll-track);
  box-shadow: inset 0 0 0 1px oklch(from var(--xp-separator) l c h / 0.55);
}

/* xp-scroll-thumb: light-blue thumb w/ horizontal gradient + centered repeating-gradient grip lines. */
@utility xp-scroll-thumb {
  border-radius: 0;
  border: 1px solid var(--xp-scroll-thumb-border);
  background-image:
    repeating-linear-gradient(180deg, oklch(from var(--xp-bevel-light) l c h / 0.9) 0 1px, transparent 1px 3px),
    linear-gradient(90deg, var(--xp-scroll-thumb-top) 0%, var(--xp-scroll-thumb-bottom) 100%);
  background-position:
    center,
    0 0;
  background-size:
    6px 10px,
    100% 100%;
  background-repeat: no-repeat;
}

/* xp-scrollbar: native-scrollbar styling for plain overflow scrollers; ScrollArea slot draws its own bars separately. */
@utility xp-scrollbar {
  scrollbar-color: var(--xp-scroll-thumb-bottom) var(--xp-scroll-track);

  &::-webkit-scrollbar {
    width: 14px;
    height: 14px;
  }

  &::-webkit-scrollbar-track {
    background: var(--xp-scroll-track);
    box-shadow: inset 0 0 0 1px oklch(from var(--xp-separator) l c h / 0.55);
  }

  &::-webkit-scrollbar-thumb {
    border: 1px solid var(--xp-scroll-thumb-border);
    background: linear-gradient(90deg, var(--xp-scroll-thumb-top) 0%, var(--xp-scroll-thumb-bottom) 100%);
  }

  &::-webkit-scrollbar-corner {
    background: var(--xp-scroll-track);
  }
}

/* "generating" treatment = library progress-sweep effect (effects.css); defaults already match XP sweep, pack re-values nothing. */

/* xp-groupbox: classic dialog groupbox groove; box needs position:relative + padding, float label over top edge yourself. */
@utility xp-groupbox {
  border-radius: 3px;
  border: 1px solid var(--xp-groupbox-border);
  box-shadow: inset 1px 1px 0 var(--xp-bevel-light);
}

/*
 * XP (Luna) owns the complete token contract under [data-skin="xp"]. Control UI core owns the
 * shared @theme bindings and dark variant; this pack owns every visual value in both modes.
 */

[data-skin="xp"] {
  /* typography — Tahoma first: the Luna system face */
  --font-sans: Tahoma, "Segoe UI", "Trebuchet MS", Verdana, ui-sans-serif, sans-serif;
  --font-mono: "Lucida Console", Consolas, monospace;

  /* type scale — Tahoma reads at the Luna 13px body rung; the other explicit rungs keep a compact hierarchy */
  --text-body: 0.8125rem; /* 13px */

  /* color — shadcn base names, full colors */
  --background: oklch(1 0 0);
  --foreground: oklch(0.2178 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.2178 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.2178 0 0);
  --primary: oklch(0.5354 0.1543 259.46); /* XP selection blue */
  --primary-foreground: oklch(1 0 0);
  --primary-text: oklch(from var(--primary) 0.48 c h);
  --muted: oklch(0.9501 0.0174 99.605);
  --muted-foreground: oklch(0.5292 0.0245 98.401);
  --secondary: oklch(0.9318 0.0228 98.65);
  --secondary-foreground: oklch(0.2178 0 0);
  --accent: oklch(0.5354 0.1543 259.46); /* XP highlight = solid selection blue with white text */
  --accent-foreground: oklch(1 0 0);
  --destructive: oklch(0.577 0.1823 25.932);
  --destructive-foreground: oklch(1 0 0);
  --destructive-text: oklch(from var(--destructive) 0.48 c h);
  --ring-opacity: 1;
  --border: oklch(0.6817 0.0116 204.079 / var(--ring-opacity));
  --input: oklch(0.6833 0.0533 246.812); /* classic field border */
  --ring: oklch(0.8118 0.1544 77.609); /* XP orange focus glow */

  /* page canvas — the XP dialog beige every panel sits on */
  --canvas: oklch(0.9318 0.0228 98.65);

  /* floating surfaces are solid in XP — no glass */
  --popover-opacity: 1;
  --backdrop-blur-popover: 0px;

  /* modal overlay — plain dim, no blur */
  --overlay-opacity: 0.3;
  --backdrop-blur-overlay: 0px;

  /* hard scroll edges: the square DA never fades clipped content */
  --scroll-fade-size: 0rem;

  /* elevation — low size, hard offset shadows */
  --shadow-color: oklch(0 0 0);
  --shadow-size: 0.4;
  --shadow-opacity: 1;
  --shadow-y: 1;
  --shadow-control-multiplier: 1;
  --shadow-panel-multiplier: 2;
  --shadow-popover-multiplier: 4;
  --shadow-modal-multiplier: 5;
  --shadow-ambient-multiplier: 8;

  /* THE one radius knob: 0 squares the whole DA. Controls consume --radius-control (0 here → square);
     buttons floor it at Luna's 3px via max(3px, --radius-control) in skin.config.tsx. So the corner is
     token-driven — raising --radius (theme editor) rounds XP controls instead of leaving them inert. */
  --radius: 0rem;
  --radius-control: calc(var(--radius) * 2);

  /* corner shape stays round — square boxes have no corner arc to reshape */
  --corner-shape: round;
  --corner-shape-control: var(--corner-shape);
  --corner-shape-popover: var(--corner-shape);
  --corner-shape-panel: var(--corner-shape);

  /* floating-list geometry: same derivations as Refined; --radius 0 collapses them to square rows/container = XP menu. */
  --popover-padding: 2px;
  --radius-popup-item: calc(var(--radius-control) * 0.6);
  --nest-safe: 1px;
  --nest-corner-ratio: 3.41421356;
  --radius-popup-item-fit: min(var(--radius-popup-item), calc(var(--control-h-xs) / 2));
  --radius-popover: calc(var(--radius-popup-item-fit) + clamp(0px, var(--radius-popup-item-fit) * 1000, var(--popover-padding) - 1px));

  /* content density — XP runs tighter than the Refined skin */
  --padding-x: 0.75rem;
  --padding-y: 0.5rem;

  /* control size scale — ONE base height; the ramp derives from it */
  --control-h: 2rem;
  /* round() to whole px so no derived step lands on a subpixel height (mirrors Refined). */
  --control-h-xs: round(var(--control-h) * 0.78, 1px);
  --control-h-sm: round(var(--control-h) * 0.89, 1px);
  --control-h-md: var(--control-h);
  --control-h-lg: round(var(--control-h) * 1.11, 1px);

  /* motion — XP does not ease: linear curves, near-instant tempos */
  --ease-standard: linear;
  --ease-emphasized: linear;
  --duration-fast: 40ms;
  --duration-base: 60ms;
  --duration-slow: 80ms;

  --popup-item-foreground: var(--foreground);
